WebBrowser.maybeCompleteAuthSession();

const OAUTH_CONFIG = {
  issuer: "https://YOUR_OAUTH_SERVER",
  authorizationEndpoint: "https://YOUR_OAUTH_SERVER/oauth2/authorize",
  tokenEndpoint: "https://YOUR_OAUTH_SERVER/oauth2/token",
  revocationEndpoint: "https://YOUR_OAUTH_SERVER/oauth2/revoke",
  clientId: "YOUR_CLIENT_ID",
  clientSecret: "YOUR_CLIENT_SECRET",
  scopes: ["openid", "profile", "offline_access"],
  extraAuthParams: {
    // audience: "YOUR_API_AUDIENCE",
  },
};

const STORAGE_KEYS = {
  tokenSet: "oauth_token_set_v1",
  pkceVerifier: "oauth_pkce_verifier_v1",
  pkceState: "oauth_pkce_state_v1",
};

function nowSeconds() {
  return Math.floor(Date.now() / 1000);
}

function parseTokenResponse(json) {
  const issuedAt = nowSeconds();
  const expiresIn = typeof json.expires_in === "number" ? json.expires_in : 3600;
  return {
    accessToken: json.access_token ?? null,
    refreshToken: json.refresh_token ?? null,
    idToken: json.id_token ?? null,
    tokenType: json.token_type ?? "Bearer",
    scope: json.scope ?? null,
    expiresIn,
    issuedAt,
  };
}

function isTokenValid(tokenSet, skewSeconds = 30) {
  if (!tokenSet?.accessToken) return false;
  if (!tokenSet?.issuedAt || !tokenSet?.expiresIn) return false;
  const exp = tokenSet.issuedAt + tokenSet.expiresIn;
  return nowSeconds() < exp - skewSeconds;
}

async function saveTokenSet(tokenSet) {
  await SecureStore.setItemAsync(STORAGE_KEYS.tokenSet, JSON.stringify(tokenSet));
}

async function loadTokenSet() {
  const raw = await SecureStore.getItemAsync(STORAGE_KEYS.tokenSet);
  if (!raw) return null;
  try {
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

async function clearTokenSet() {
  await SecureStore.deleteItemAsync(STORAGE_KEYS.tokenSet);
}

function base64UrlEncode(bytes) {
  const base64 = Buffer.from(bytes).toString("base64");
  return base64.replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/g, "");
}

async function createPkcePair() {
  const randomBytes = await Crypto.getRandomBytesAsync(32);
  const verifier = base64UrlEncode(randomBytes);
  const digest = await Crypto.digestStringAsync(Crypto.CryptoDigestAlgorithm.SHA256, verifier, {
    encoding: Crypto.CryptoEncoding.BASE64,
  });
  const challenge = digest.replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/g, "");
  return { verifier, challenge, method: "S256" };
}

function formUrlEncode(params) {
  const sp = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v === undefined || v === null) return;
    sp.append(k, String(v));
  });
  return sp.toString();
}

async function tokenRequest(params) {
  const body = formUrlEncode(params);
  const res = await fetch(OAUTH_CONFIG.tokenEndpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
    },
    body,
  });
  const json = await res.json().catch(() => ({}));
  if (!res.ok) {
    const message = json?.error_description || json?.error || `Token endpoint error (${res.status})`;
    throw new Error(message);
  }
  return json;
}

async function exchangeAuthorizationCode({ code, redirectUri, codeVerifier }) {
  const json = await tokenRequest({
    grant_type: "authorization_code",
    code,
    redirect_uri: redirectUri,
    client_id: OAUTH_CONFIG.clientId,
    client_secret: OAUTH_CONFIG.clientSecret,
    code_verifier: codeVerifier,
  });
  return parseTokenResponse(json);
}

async function refreshAccessToken({ refreshToken }) {
  const json = await tokenRequest({
    grant_type: "refresh_token",
    refresh_token: refreshToken,
    client_id: OAUTH_CONFIG.clientId,
    client_secret: OAUTH_CONFIG.clientSecret,
  });
  return parseTokenResponse(json);
}

async function revokeToken(token) {
  if (!OAUTH_CONFIG.revocationEndpoint) return;
  try {
    await fetch(OAUTH_CONFIG.revocationEndpoint, {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: formUrlEncode({
        token,
        client_id: OAUTH_CONFIG.clientId,
        client_secret: OAUTH_CONFIG.clientSecret,
      }),
    });
  } catch {}
}

function buildAuthorizeUrl({ redirectUri, state, codeChallenge }) {
  const url = new URL(OAUTH_CONFIG.authorizationEndpoint);
  url.searchParams.set("response_type", "code");
  url.searchParams.set("client_id", OAUTH_CONFIG.clientId);
  url.searchParams.set("redirect_uri", redirectUri);
  url.searchParams.set("scope", OAUTH_CONFIG.scopes.join(" "));
  url.searchParams.set("state", state);
  url.searchParams.set("code_challenge", codeChallenge);
  url.searchParams.set("code_challenge_method", "S256");
  Object.entries(OAUTH_CONFIG.extraAuthParams || {}).forEach(([k, v]) => {
    if (v !== undefined && v !== null) url.searchParams.set(k, String(v));
  });
  return url.toString();
}

function useInterval(callback, delay) {
  const savedCallback = useRef(callback);
  useEffect(() => {
    savedCallback.current = callback;
  }, [callback]);

  useEffect(() => {
    if (delay == null) return;
    const id = setInterval(() => savedCallback.current(), delay);
    return () => clearInterval(id);
  }, [delay]);
}

export default function App() {
  const [busy, setBusy] = useState(false);
  const [tokenSet, setTokenSet] = useState(null);
  const [error, setError] = useState(null);

  const redirectUri = useMemo(
    () => AuthSession.makeRedirectUri({ scheme: "yourapp" }),
    []
  );

  const hydrate = useCallback(async () => {
    const stored = await loadTokenSet();
    setTokenSet(stored);
  }, []);

  useEffect(() => {
    hydrate();
  }, [hydrate]);

  const ensureFreshToken = useCallback(async () => {
    const current = await loadTokenSet();
    if (!current) return null;
    if (isTokenValid(current)) {
      setTokenSet(current);
      return current;
    }
    if (!current.refreshToken) {
      setTokenSet(current);
      return current;
    }
    const refreshed = await refreshAccessToken({ refreshToken: current.refreshToken });
    const merged = {
      ...current,
      ...refreshed,
      refreshToken: refreshed.refreshToken || current.refreshToken,
    };
    await saveTokenSet(merged);
    setTokenSet(merged);
    return merged;
  }, []);

  useInterval(() => {
    ensureFreshToken().catch(() => {});
  }, 15000);

  const signIn = useCallback(async () => {
    setBusy(true);
    setError(null);
    try {
      const stateBytes = await Crypto.getRandomBytesAsync(16);
      const state = base64UrlEncode(stateBytes);
      const pkce = await createPkcePair();

      await SecureStore.setItemAsync(STORAGE_KEYS.pkceVerifier, pkce.verifier);
      await SecureStore.setItemAsync(STORAGE_KEYS.pkceState, state);

      const authorizeUrl = buildAuthorizeUrl({
        redirectUri,
        state,
        codeChallenge: pkce.challenge,
      });

      const result = await AuthSession.startAsync({
        authUrl: authorizeUrl,
        returnUrl: redirectUri,
      });

      if (result.type !== "success") {
        throw new Error(result.type === "dismiss" ? "Login canceled" : "Authorization failed");
      }

      const params = result.params || {};
      if (params.error) {
        throw new Error(params.error_description || params.error);
      }

      const returnedState = params.state;
      const storedState = await SecureStore.getItemAsync(STORAGE_KEYS.pkceState);
      if (!returnedState || !storedState || returnedState !== storedState) {
        throw new Error("Invalid state");
      }

      const code = params.code;
      if (!code) throw new Error("Missing authorization code");

      const codeVerifier = await SecureStore.getItemAsync(STORAGE_KEYS.pkceVerifier);
      if (!codeVerifier) throw new Error("Missing PKCE verifier");

      const exchanged = await exchangeAuthorizationCode({
        code,
        redirectUri,
        codeVerifier,
      });

      await saveTokenSet(exchanged);
      setTokenSet(exchanged);
    } catch (e) {
      setError(e?.message || String(e));
    } finally {
      setBusy(false);
    }
  }, [redirectUri]);

  const signOut = useCallback(async () => {
    setBusy(true);
    setError(null);
    try {
      const current = await loadTokenSet();
      if (current?.refreshToken) await revokeToken(current.refreshToken);
      if (current?.accessToken) await revokeToken(current.accessToken);
      await clearTokenSet();
      setTokenSet(null);
    } catch (e) {
      setError(e?.message || String(e));
    } finally {
      setBusy(false);
    }
  }, []);

  const callApi = useCallback(async () => {
    setBusy(true);
    setError(null);
    try {
      const fresh = await ensureFreshToken();
      if (!fresh?.accessToken) throw new Error("Not authenticated");

      const res = await fetch("https://YOUR_API_SERVER/protected", {
        headers: {
          Authorization: `${fresh.tokenType || "Bearer"} ${fresh.accessToken}`,
        },
      });
      const text = await res.text();
      Alert.alert("API Response", `${res.status}\n\n${text}`.slice(0, 3500));
    } catch (e) {
      setError(e?.message || String(e));
    } finally {
      setBusy(false);
    }
  }, [ensureFreshToken]);

  const status = useMemo(() => {
    if (!tokenSet?.accessToken) return "Signed out";
    const exp = tokenSet.issuedAt && tokenSet.expiresIn ? tokenSet.issuedAt + tokenSet.expiresIn : null;
    return `Signed in\nAccess token ${isTokenValid(tokenSet) ? "valid" : "expired"}${exp ? `\nExpires at: ${new Date(exp * 1000).toISOString()}` : ""}`;
  }, [tokenSet]);

  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView contentContainerStyle={styles.container}>
        <Text style={styles.title}>OAuth 2.0 Authorization Code (PKCE)</Text>
        <Text style={styles.sub}>
          Redirect URI: {redirectUri}
        </Text>

        <View style={styles.card}>
          <Text style={styles.status}>{status}</Text>

          {busy ? (
            <View style={styles.row}>
              <ActivityIndicator />
              <Text style={styles.busyText}>Working…</Text>
            </View>
          ) : null}

          {error ? <Text style={styles.error}>{error}</Text> : null}

          <View style={styles.buttons}>
            <View style={styles.button}>
              <Button title="Sign In" onPress={signIn} disabled={busy} />
            </View>
            <View style={styles.button}>
              <Button title="Call Protected API" onPress={callApi} disabled={busy || !tokenSet?.accessToken} />
            </View>
            <View style={styles.button}>
              <Button title="Sign Out" onPress={signOut} disabled={busy} />
            </View>
          </View>
        </View>

        <View style={styles.card}>
          <Text style={styles.monoLabel}>Token Set (stored in SecureStore)</Text>
          <Text style={styles.mono}>
            {tokenSet ? JSON.stringify(tokenSet, null, 2) : "null"}
          </Text>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

